func TestValidateToolsAllowed(t *testing.T) {
	tests := []struct {
		name        string
		calls       []teams.ToolCall
		allowed     []string
		wantErr     bool
		errContains string
	}{
		{
			name: "all tools allowed",
			calls: []teams.ToolCall{
				{ID: "call-1", Name: "graph_query"},
				{ID: "call-2", Name: "file_read"},
			},
			allowed: []string{"graph_query", "file_read", "file_write"},
			wantErr: false,
		},
		{
			name: "single tool allowed",
			calls: []teams.ToolCall{
				{ID: "call-1", Name: "graph_query"},
			},
			allowed: []string{"graph_query"},
			wantErr: false,
		},
		{
			name:    "empty calls allowed",
			calls:   []teams.ToolCall{},
			allowed: []string{"graph_query"},
			wantErr: false,
		},
		{
			name:    "nil calls allowed",
			calls:   nil,
			allowed: []string{"graph_query"},
			wantErr: false,
		},
		{
			name: "single disallowed tool",
			calls: []teams.ToolCall{
				{ID: "call-1", Name: "file_delete"},
			},
			allowed:     []string{"graph_query", "file_read"},
			wantErr:     true,
			errContains: "file_delete",
		},
		{
			name: "multiple disallowed tools",
			calls: []teams.ToolCall{
				{ID: "call-1", Name: "file_delete"},
				{ID: "call-2", Name: "system_exec"},
			},
			allowed:     []string{"graph_query"},
			wantErr:     true,
			errContains: "file_delete",
		},
		{
			name: "mix of allowed and disallowed",
			calls: []teams.ToolCall{
				{ID: "call-1", Name: "graph_query"},
				{ID: "call-2", Name: "file_delete"},
				{ID: "call-3", Name: "file_read"},
			},
			allowed:     []string{"graph_query", "file_read"},
			wantErr:     true,
			errContains: "file_delete",
		},
		{
			name: "empty allowed list blocks all",
			calls: []teams.ToolCall{
				{ID: "call-1", Name: "graph_query"},
			},
			allowed:     []string{},
			wantErr:     true,
			errContains: "graph_query",
		},
		{
			name: "nil allowed list blocks all",
			calls: []teams.ToolCall{
				{ID: "call-1", Name: "graph_query"},
			},
			allowed:     nil,
			wantErr:     true,
			errContains: "graph_query",
		},
		{
			name: "case sensitive matching",
			calls: []teams.ToolCall{
				{ID: "call-1", Name: "Graph_Query"},
			},
			allowed:     []string{"graph_query"},
			wantErr:     true,
			errContains: "Graph_Query",
		},
		{
			name: "duplicate tool calls allowed",
			calls: []teams.ToolCall{
				{ID: "call-1", Name: "graph_query"},
				{ID: "call-2", Name: "graph_query"},
			},
			allowed: []string{"graph_query"},
			wantErr: false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			err := teams.ValidateToolsAllowed(tt.calls, tt.allowed)
			if tt.wantErr {
				if err == nil {
					t.Errorf("ValidateToolsAllowed() expected error, got nil")
					return
				}
				if tt.errContains != "" {
					errMsg := err.Error()
					if len(errMsg) == 0 || errMsg[:1] != errMsg[:1] {
						// Check contains
						found := false
						for i := 0; i <= len(errMsg)-len(tt.errContains); i++ {
							if errMsg[i:i+len(tt.errContains)] == tt.errContains {
								found = true
								break
							}
						}
						if !found {
							t.Errorf("ValidateToolsAllowed() error = %v, want to contain %v", errMsg, tt.errContains)
						}
					}
				}
			} else {
				if err != nil {
					t.Errorf("ValidateToolsAllowed() unexpected error = %v", err)
				}
			}
		})
	}
}

